  .grid-3{display:grid;grid-template-columns:repeat(3,1fr);gap:18px}.feature-card,.simple-card,.package,.testimonial,.faq-item,.contact-card{background:#fff;border:1px solid var(--line);border-radius:var(--radius);box-shadow:0 10px 28px rgba(16,24,40,.05)}.feature-card{padding:24px}.icon{width:50px;height:50px;border-radius:16px;display:grid;place-items:center;background:var(--green-soft);color:var(--green);font-size:24px;margin-bottom:18px}.feature-card h3,.simple-card h3{margin:0 0 9px;font-size:20px}.feature-card p,.simple-card p{margin:0;color:var(--muted);line-height:1.6}
