  .testimonials{display:grid;grid-template-columns:repeat(3,1fr);gap:18px}.testimonial{padding:24px}.quote{font-size:34px;color:var(--green);line-height:1}.testimonial p{color:#475467;line-height:1.65}.person{display:flex;gap:12px;align-items:center;margin-top:18px}.person-avatar{width:42px;height:42px;border-radius:50%;background:var(--green-soft);color:var(--green);display:grid;place-items:center;font-weight:900}.person strong{display:block}.person span{color:var(--muted);font-size:13px}
