  .footer{background:#0b1220;color:#cbd5e1;padding:36px 0}.footer-grid{display:flex;justify-content:space-between;gap:22px;align-items:flex-start}.footer strong{color:#fff}.footer p{margin:8px 0 0;color:#94a3b8;line-height:1.6}.footer-links{display:flex;gap:18px;flex-wrap:wrap}.hidden{display:none!important}
